import React, { useEffect, useState } from 'react';
import API from '../utils/api';

const MOCK_STUDENTS = [
  { name: 'Priya S.', cgpa: 9.1, placement: 94, tests: 12, branch: 'CSE', badge: '🏆' },
  { name: 'Rahul M.', cgpa: 8.8, placement: 89, tests: 10, branch: 'IT', badge: '🥈' },
  { name: 'Sneha K.', cgpa: 8.5, placement: 85, tests: 9, branch: 'ECE', badge: '🥉' },
  { name: 'Arjun P.', cgpa: 8.2, placement: 82, tests: 11, branch: 'CSE', badge: '⭐' },
  { name: 'Divya R.', cgpa: 8.0, placement: 79, tests: 8, branch: 'MECH', badge: '⭐' },
  { name: 'Karthik N.', cgpa: 7.8, placement: 75, tests: 7, branch: 'CSE', badge: '⭐' },
  { name: 'Meena T.', cgpa: 7.5, placement: 71, tests: 9, branch: 'IT', badge: '⭐' },
  { name: 'Vijay L.', cgpa: 7.2, placement: 68, tests: 6, branch: 'ECE', badge: '' },
  { name: 'Ananya B.', cgpa: 7.0, placement: 64, tests: 5, branch: 'CSE', badge: '' },
  { name: 'Rohan G.', cgpa: 6.8, placement: 59, tests: 4, branch: 'CIVIL', badge: '' },
  { name: 'Lakshmi V.', cgpa: 6.5, placement: 55, tests: 7, branch: 'CSE', badge: '' },
  { name: 'Suresh A.', cgpa: 6.2, placement: 50, tests: 3, branch: 'MECH', badge: '' },
];

export default function Leaderboard() {
  const [profile, setProfile] = useState(null);
  const [testResults, setTestResults] = useState([]);
  const [sortBy, setSortBy] = useState('placement');
  const [myRank, setMyRank] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/profile').then(res => {
      setProfile(res.data.profile);
      setTestResults(res.data.test_results || []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const getMyScore = () => {
    if (!profile) return null;
    const avgTest = testResults.length > 0
      ? Math.round(testResults.reduce((s, t) => s + (t.score / t.total) * 100, 0) / testResults.length)
      : 0;
    return {
      name: 'You',
      cgpa: profile.cgpa || 0,
      placement: profile.placement_probability || 0,
      tests: testResults.length,
      branch: profile.branch || 'N/A',
      badge: '',
      avgTest,
      isMe: true,
    };
  };

  const getLeaderboardData = () => {
    const me = getMyScore();
    const allStudents = MOCK_STUDENTS.map(s => ({ ...s, avgTest: Math.round(60 + Math.random() * 30), isMe: false }));
    if (me) allStudents.push(me);

    const sorted = allStudents.sort((a, b) => {
      if (sortBy === 'placement') return b.placement - a.placement;
      if (sortBy === 'cgpa') return b.cgpa - a.cgpa;
      if (sortBy === 'tests') return b.tests - a.tests;
      return b.placement - a.placement;
    });

    const ranked = sorted.map((s, i) => ({ ...s, rank: i + 1 }));
    const myEntry = ranked.find(s => s.isMe);
    if (myEntry) setMyRank(myEntry.rank);
    return ranked;
  };

  const data = getLeaderboardData();
  const me = data.find(s => s.isMe);

  const getRankStyle = (rank) => {
    if (rank === 1) return { bg: 'rgba(255,215,0,0.1)', border: 'rgba(255,215,0,0.4)', color: '#ffd700' };
    if (rank === 2) return { bg: 'rgba(192,192,192,0.1)', border: 'rgba(192,192,192,0.3)', color: '#c0c0c0' };
    if (rank === 3) return { bg: 'rgba(205,127,50,0.1)', border: 'rgba(205,127,50,0.3)', color: '#cd7f32' };
    return { bg: 'transparent', border: 'var(--border)', color: 'var(--text3)' };
  };

  if (loading) return (
    <div style={{ display:'flex', justifyContent:'center', alignItems:'center', height:300, flexDirection:'column', gap:16 }}>
      <div style={{ width:40, height:40, border:'3px solid var(--border)', borderTop:'3px solid var(--accent)', borderRadius:'50%', animation:'spin 0.8s linear infinite' }} />
    </div>
  );

  return (
    <div className="content-area fade-in">
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:20, flexWrap:'wrap', gap:12 }}>
        <div>
          <h1 className="section-title">🏆 Leaderboard</h1>
          <p className="section-sub">See how you rank among students on the platform</p>
        </div>
        {me && (
          <div style={{ background:'rgba(99,102,241,0.15)', border:'1px solid rgba(99,102,241,0.3)', borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:26, fontWeight:800, color:'var(--accent)' }}>#{myRank}</div>
            <div style={{ fontSize:11, color:'var(--text3)' }}>Your Rank</div>
          </div>
        )}
      </div>

      {/* My stats snapshot */}
      {me && (
        <div className="card" style={{ marginBottom:20, background:'rgba(99,102,241,0.08)', border:'1px solid rgba(99,102,241,0.2)' }}>
          <div style={{ fontWeight:700, fontSize:14, marginBottom:14, color:'#a5b4fc' }}>📊 Your Stats at a Glance</div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:12 }}>
            {[
              ['🎓', 'CGPA', me.cgpa || 'N/A'],
              ['🤖', 'AI Prediction', `${me.placement}%`],
              ['📝', 'Tests Taken', me.tests],
              ['🏅', 'Your Rank', `#${myRank} of ${data.length}`],
            ].map(([icon, label, val]) => (
              <div key={label} style={{ textAlign:'center', background:'var(--card)', borderRadius:10, padding:'14px 8px' }}>
                <div style={{ fontSize:22 }}>{icon}</div>
                <div style={{ fontSize:18, fontWeight:800, color:'var(--accent)', marginTop:4 }}>{val}</div>
                <div style={{ fontSize:11, color:'var(--text3)' }}>{label}</div>
              </div>
            ))}
          </div>
          {myRank > 5 && (
            <div style={{ marginTop:14, padding:'10px 14px', background:'rgba(245,158,11,0.1)', border:'1px solid rgba(245,158,11,0.2)', borderRadius:8, fontSize:13, color:'#fcd34d' }}>
              💡 You are <strong>{myRank - 1} positions</strong> away from the top 3. Take more tests and improve your profile to climb up!
            </div>
          )}
          {myRank <= 3 && (
            <div style={{ marginTop:14, padding:'10px 14px', background:'rgba(16,185,129,0.1)', border:'1px solid rgba(16,185,129,0.2)', borderRadius:8, fontSize:13, color:'#10b981' }}>
              🎉 Amazing! You are in the <strong>Top 3</strong> on the leaderboard. Keep it up!
            </div>
          )}
        </div>
      )}

      {/* Sort options */}
      <div className="card" style={{ marginBottom:20, padding:'12px 16px' }}>
        <div style={{ display:'flex', gap:8, alignItems:'center' }}>
          <span style={{ fontSize:13, color:'var(--text2)', fontWeight:600 }}>Sort by:</span>
          {[['placement','🤖 AI Score'],['cgpa','🎓 CGPA'],['tests','📝 Tests Taken']].map(([val, label]) => (
            <button key={val} onClick={() => setSortBy(val)}
              style={{ padding:'6px 14px', borderRadius:20, fontSize:12, fontWeight:600, cursor:'pointer', border:'none', background:sortBy===val?'var(--accent)':'var(--bg2)', color:sortBy===val?'white':'var(--text2)', fontFamily:'Outfit,sans-serif' }}>
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* Leaderboard table */}
      <div className="card" style={{ padding:0, overflow:'hidden' }}>
        <div style={{ padding:'14px 20px', borderBottom:'1px solid var(--border)', display:'grid', gridTemplateColumns:'60px 1fr 80px 80px 80px 80px', gap:8, fontSize:11, fontWeight:700, color:'var(--text3)' }}>
          <div>RANK</div><div>STUDENT</div><div style={{ textAlign:'center' }}>CGPA</div><div style={{ textAlign:'center' }}>AI SCORE</div><div style={{ textAlign:'center' }}>TESTS</div><div style={{ textAlign:'center' }}>BRANCH</div>
        </div>
        {data.map((student, i) => {
          const rs = getRankStyle(student.rank);
          return (
            <div key={i}
              style={{ padding:'14px 20px', display:'grid', gridTemplateColumns:'60px 1fr 80px 80px 80px 80px', gap:8, alignItems:'center', borderBottom:'1px solid var(--bg2)', background:student.isMe?'rgba(99,102,241,0.08)':rs.bg, borderLeft:student.isMe?'3px solid var(--accent)':'3px solid transparent', transition:'background 0.2s' }}>
              <div style={{ fontFamily:'Space Grotesk', fontWeight:800, fontSize:16, color:rs.color }}>
                {student.rank <= 3 ? ['🥇','🥈','🥉'][student.rank-1] : `#${student.rank}`}
              </div>
              <div>
                <div style={{ fontWeight:700, fontSize:14, display:'flex', gap:6, alignItems:'center' }}>
                  {student.name} {student.isMe && <span style={{ fontSize:10, background:'var(--accent)', color:'white', padding:'2px 6px', borderRadius:10 }}>YOU</span>}
                  {student.badge && <span>{student.badge}</span>}
                </div>
              </div>
              <div style={{ textAlign:'center', fontWeight:700, color:student.cgpa>=8?'#10b981':student.cgpa>=7?'#f59e0b':'var(--text)' }}>{student.cgpa}</div>
              <div style={{ textAlign:'center' }}>
                <span style={{ fontWeight:700, color:student.placement>=80?'#10b981':student.placement>=60?'#f59e0b':'var(--text)' }}>{Math.round(student.placement)}%</span>
              </div>
              <div style={{ textAlign:'center', color:'var(--text2)' }}>{student.tests}</div>
              <div style={{ textAlign:'center', fontSize:11, color:'var(--text3)', background:'var(--bg2)', padding:'3px 8px', borderRadius:10 }}>{student.branch}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
